/// Look for patterns like
///   %sel1 = select i1 %c1, i32 %a, i32 %b
///   %sel2 = select i1 %c1, i32 %b, i32 %a
///   %ret = select i1 %c2, i32 %sel1, i32 %sel2
/// and optimize it to:
///   %xor = xor i1 %c1, %c2
///   %ret = select i1 %xor, i32 %b, i32 %a
static Instruction *foldSelectOfSymmetricSelects(SelectInst &OuterSel,
                                                 InstCombiner::BuilderTy &Builder) {
  // Outer select: %ret = select %c2, %sel1, %sel2
  Value *OuterCond = OuterSel.getCondition();
  Value *TrueVal = OuterSel.getTrueValue();
  Value *FalseVal = OuterSel.getFalseValue();

  // Both true and false values must be select instructions.
  auto *TrueSel = dyn_cast<SelectInst>(TrueVal);
  auto *FalseSel = dyn_cast<SelectInst>(FalseVal);
  if (!TrueSel || !FalseSel)
    return nullptr;

  // They must have the same condition.
  if (TrueSel->getCondition() != FalseSel->getCondition())
    return nullptr;
  Value *InnerCond = TrueSel->getCondition();

  // The true value of one must be the false value of the other, and vice versa.
  if (TrueSel->getTrueValue() != FalseSel->getFalseValue() ||
      TrueSel->getFalseValue() != FalseSel->getTrueValue())
    return nullptr;

  // Now we have:
  //   %sel1 = select %c1, %a, %b
  //   %sel2 = select %c1, %b, %a
  //   %ret = select %c2, %sel1, %sel2
  // This is equivalent to:
  //   %cond = xor %c1, %c2
  //   %ret = select %cond, %b, %a
  Value *A = TrueSel->getTrueValue();
  Value *B = TrueSel->getFalseValue();
  Value *XorCond = Builder.CreateXor(InnerCond, OuterCond);
  Value *NewSelect = Builder.CreateSelect(XorCond, B, A);
  NewSelect->takeName(&OuterSel);
  return cast<Instruction>(NewSelect);
}

